        <main class="main">
            <div class="content-header"><div class="page-title">🛒 Sales Report</div></div>
            <div class="content-body">
                <div class="toolbar"><label style="font-size:13px;font-weight:600">From</label><input type="date" id="date-from" onchange="gen()"><label style="font-size:13px;font-weight:600">To</label><input type="date" id="date-to" onchange="gen()"><button class="btn btn-primary" onclick="gen()">Generate</button><button class="btn btn-outline" onclick="window.print()">🖨 Print</button><button class="btn btn-outline" onclick="exportCSV()">📥 Export</button></div>
                <div class="stats-row">
                    <div class="stat-card"><div class="stat-label">Total Sales</div><div class="stat-value" id="s-count">0</div></div>
                    <div class="stat-card"><div class="stat-label">Revenue</div><div class="stat-value" id="s-total" style="color:#16a34a">LKR 0</div></div>
                    <div class="stat-card"><div class="stat-label">Avg. Sale</div><div class="stat-value" id="s-avg">LKR 0</div></div>
                    <div class="stat-card"><div class="stat-label">Items Sold</div><div class="stat-value" id="s-items">0</div></div>
                </div>
                <div class="card">
                    <table><thead><tr><th>#</th><th>Date</th><th>Invoice</th><th>Customer</th><th>Method</th><th>Items</th><th>Total</th><th>Status</th></tr></thead><tbody id="report-tbody"></tbody></table>
                    <div class="empty-state" id="empty">No sales data for selected period.</div>
                    <div style="margin-top:12px;padding-top:10px;border-top:2px solid #e5e7eb;text-align:right;font-size:15px;font-weight:700" id="grand-total"></div>
                </div>
