    <script src="assets/js/utils.js"></script><script src="assets/js/auth.js"></script><script src="assets/js/toast.js"></script>
    <script>
    document.addEventListener('DOMContentLoaded',()=>{Auth.requireAuth();const s=Auth.getSession();if(s&&s.user){document.getElementById('nav-username').textContent=s.user.name||s.user.username;document.getElementById('nav-avatar').textContent=(s.user.name||s.user.username).charAt(0).toUpperCase();}document.getElementById('nav-date').textContent=new Date().toLocaleDateString('en-GB');document.getElementById('sidebar-toggle').addEventListener('click',()=>{const sb=document.getElementById('sidebar');if(window.innerWidth<=768)sb.classList.toggle('mobile-open');else sb.classList.toggle('collapsed');});document.getElementById('nav-user').addEventListener('click',()=>{if(confirm('Logout?'))Auth.logout();});const n=new Date();document.getElementById('date-from').value=new Date(n.getFullYear(),n.getMonth(),1).toISOString().split('T')[0];document.getElementById('date-to').value=n.toISOString().split('T')[0];gen();});
    function toggleMenu(id){const i=document.querySelector(`[data-menu="${id}"]`);if(!i)return;const w=i.classList.contains('open');document.querySelectorAll('.menu-item.open').forEach(e=>e.classList.remove('open'));if(!w)i.classList.add('open');}
    function fmtC(v){return 'LKR '+parseFloat(v||0).toLocaleString('en-LK',{minimumFractionDigits:2});}
    function gen(){
        const f=document.getElementById('date-from').value,t=document.getElementById('date-to').value;
        const all=JSON.parse(localStorage.getItem('jr_sales')||'[]').filter(s=>(!f||s.date>=f)&&(!t||s.date<=t));
        const total=all.reduce((s,x)=>s+parseFloat(x.total||0),0);
        const totalItems=all.reduce((s,x)=>s+(x.items||[]).reduce((a,it)=>a+(it.qty||0),0),0);
        document.getElementById('s-count').textContent=all.length;
        document.getElementById('s-total').textContent=fmtC(total);
        document.getElementById('s-avg').textContent=fmtC(all.length?total/all.length:0);
        document.getElementById('s-items').textContent=totalItems;
        const tb=document.getElementById('report-tbody'),em=document.getElementById('empty');
        if(!all.length){tb.innerHTML='';em.style.display='';document.getElementById('grand-total').innerHTML='';return;}
        em.style.display='none';
        tb.innerHTML=all.map((s,i)=>{const badge=s.status==='completed'?'background:#dcfce7;color:#16a34a':'background:#fef9c3;color:#ca8a04';return`<tr><td>${i+1}</td><td>${s.date}</td><td style="font-family:monospace">${s.invoice||s.id}</td><td>${s.customer||'Walk-in'}</td><td>${s.method||'Cash'}</td><td>${(s.items||[]).length}</td><td style="font-weight:600">${fmtC(s.total)}</td><td><span style="${badge};padding:2px 10px;border-radius:20px;font-size:11px;font-weight:600">${s.status||'—'}</span></td></tr>`;}).join('');
        document.getElementById('grand-total').innerHTML='Grand Total: '+fmtC(total);
    }
    function exportCSV(){const all=JSON.parse(localStorage.getItem('jr_sales')||'[]');if(!all.length){Toast.warning('No data');return;}const c='Date,Invoice,Customer,Method,Items,Total,Status\n'+all.map(s=>`"${s.date}","${s.invoice||s.id}","${s.customer||'Walk-in'}","${s.method||'Cash'}",${(s.items||[]).length},${s.total},"${s.status||''}"`).join('\n');const b=new Blob([c],{type:'text/csv'});const a=document.createElement('a');a.href=URL.createObjectURL(b);a.download='sales-report.csv';a.click();}
    </script>
